import{_ as a,o as s,c as t,a2 as i}from"./chunks/framework.Dj2sMFyx.js";const u=JSON.parse('{"title":"Current Kandelo UI","description":"","frontmatter":{},"headers":[],"relativePath":"guide/current-ui.md","filePath":"guide/current-ui.md","lastUpdated":1784914006000}'),n={name:"guide/current-ui.md"};function r(l,e,o,p,d,h){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="current-kandelo-ui" tabindex="-1">Current Kandelo UI <a class="header-anchor" href="#current-kandelo-ui" aria-label="Permalink to &quot;Current Kandelo UI&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">API stability</p><p>The Kandelo UI and every browser-facing boot URL shape documented here are experimental. They are useful today, but they are not a long-term compatibility promise.</p></div><p>The public Kandelo UI is available at:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://automattic.github.io/kandelo/</span></span></code></pre></div><p>It boots prebuilt machines in the browser using <code>kernel.wasm</code>, package artifacts, and VFS images. The first screen lets users boot a preset, paste a Kandelo URL, or bring a VFS image.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Kandelo needs browser support for <code>SharedArrayBuffer</code>. In practice the page must be cross-origin isolated:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cross-Origin-Opener-Policy: same-origin</span></span>
<span class="line"><span>Cross-Origin-Embedder-Policy: require-corp</span></span></code></pre></div><p>The GitHub Pages deployment uses a service worker to add the required isolation headers. If the page reports that <code>SharedArrayBuffer</code> is unavailable, clear site data and reload. A stale service worker can keep old behavior alive.</p><h2 id="local-development" tabindex="-1">Local Development <a class="header-anchor" href="#local-development" aria-label="Permalink to &quot;Local Development&quot;">​</a></h2><p>From a Kandelo checkout:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./run.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> browser</span></span></code></pre></div><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:5401/</span></span></code></pre></div><p><code>./run.sh browser</code> prepares missing browser artifacts before starting Vite. The lower-level path is:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps/browser-demos</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>That path assumes the needed kernel, rootfs, package, and VFS artifacts already exist.</p><h2 id="gallery-presets" tabindex="-1">Gallery Presets <a class="header-anchor" href="#gallery-presets" aria-label="Permalink to &quot;Gallery Presets&quot;">​</a></h2><p>The current UI ships local gallery presets such as:</p><ul><li>Bare shell</li><li>Node.js</li><li>nginx</li><li>nginx + PHP</li><li>WordPress SQLite</li><li>WordPress MariaDB</li><li>fbDOOM</li></ul><p>When a user launches a preset, the UI selects a VFS image, boots the kernel, starts the configured process, and presents the relevant surfaces:</p><ul><li>terminal</li><li>web preview for HTTP demos</li><li>syslog and process internals</li><li>VFS browser</li><li>framebuffer, mouse, keyboard, and audio for demos that expose those devices</li></ul><h2 id="direct-vfs-links" tabindex="-1">Direct VFS Links <a class="header-anchor" href="#direct-vfs-links" aria-label="Permalink to &quot;Direct VFS Links&quot;">​</a></h2><p>The UI can boot a direct VFS image URL without a gallery manifest:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://automattic.github.io/kandelo/?vfs=https://example.com/images/site.vfs.zst</span></span></code></pre></div><p>Accepted image URL schemes are <code>http</code> and <code>https</code>. The image should be a <code>.vfs</code> or <code>.vfs.zst</code> file produced by Kandelo&#39;s VFS tooling.</p><p>The host serving the image must allow the browser to fetch it from a cross-origin-isolated page. Use CORS or compatible cross-origin resource policy headers.</p><h2 id="external-software-manifests" tabindex="-1">External Software Manifests <a class="header-anchor" href="#external-software-manifests" aria-label="Permalink to &quot;External Software Manifests&quot;">​</a></h2><p>The UI can load gallery entries from package-source repositories:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://automattic.github.io/kandelo/?softwareManifest=https://example.com/releases/download/binaries-abi-v11/gallery.json</span></span></code></pre></div><p>Multiple manifest URLs can be supplied with repeated <code>softwareManifest</code> parameters or a comma/whitespace-separated value in local builds through:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VITE_KANDELO_SOFTWARE_MANIFEST_URLS</span></span></code></pre></div><p>The gallery shows an external entry only when every package named by that entry has a successful <code>wasm32</code> record in the matching <code>index.toml</code>.</p><h2 id="network-behavior" tabindex="-1">Network Behavior <a class="header-anchor" href="#network-behavior" aria-label="Permalink to &quot;Network Behavior&quot;">​</a></h2><p>Browser Kandelo supports local loopback sockets and virtual machine-to-machine networking inside the browser session. Browser sandboxing prevents raw external TCP and UDP sockets. External network use goes through fetch, the service worker HTTP bridge, a CORS proxy, or future transport backends.</p><p>The browser app defaults cross-origin fetches to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://wordpress-playground-cors-proxy.net/?</span></span></code></pre></div><p>For local development:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps/browser-demos</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VITE_CORS_PROXY_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://your-proxy.example/?&#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div>`,39)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
